def t(code: str, key: str, **kwargs) -> str:
    """Get localized string by language code and key."""
    locale = LOCALES.get(code, LOCALES.get("en"))
    template = locale.get(key, LOCALES["en"].get(key, key))
    try:
        return template.format(**kwargs)
    except Exception:
        return template
